import React from "react"
import TheoPlayer from "./TheoPlayer"
import poster from "../assets/images/course-main.jpg"
import mute from "../assets/images/mute.png"
import maximize from "../assets/images/maximize.png"
import { Button } from "carbon-components-react"

const source = {
  sources: [
    {
      src: "//cdn.theoplayer.com/video/elephants-dream/playlist.m3u8",
      type: "application/x-mpegurl"
    }
  ],
  poster: poster
}

const IconMute = () => <img src={mute} alt="mute" />
const IconMaximize = () => <img src={maximize} alt="maimize" />

export default function CoursePlayer() {
  const handleOnPlay = () => {}

  return (
    <div className="theo-player">
      <TheoPlayer
        source={source}
        autoplay={true}
        onPlaying={handleOnPlay}
        style={{ opacity: 0 }}
      />
      <div className="player-top-layer" />
      <div className="player-content-layer">
        <h2>SeloJéne</h2>
        <div className="player-action bx--grid bx--grid--narrow">
          <div className="bx--row">
            <div className="bx--col-lg-3 bx--col-md-2 bx--col-sm-4">
              <div className="buy-access-container">
                <Button className="buy-access">Buy Access</Button>
                <p>IDR 199,000 for 1 year</p>
              </div>
            </div>

            <div className="bx--col-lg-7 bx--col-md-5 bx--col-sm-4">
              <p>{`Learn and get insights about architecture and interior design from SeloJene, located in the small town Salatiga, Indonesia, the residence of Ary Indra, the founder of Aboday, and the head curator of the Indonesian Pavilion at Venice Architectur Biennale 2018.`}</p>
            </div>

            <div className="bx--col-lg-1 bx--col-md-1 bx--col-sm-0">
              <div className="player-icons">
                <Button
                  hasIconOnly
                  renderIcon={IconMute}
                  kind="ghost"
                  tooltipAlignment="center"
                  tooltipPosition="bottom"
                  iconDescription="mute sound"
                />
                <Button
                  hasIconOnly
                  renderIcon={IconMaximize}
                  kind="ghost"
                  tooltipAlignment="center"
                  tooltipPosition="bottom"
                  iconDescription="mute sound"
                />
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}
