import React from "react"
import { Link } from "carbon-components-react"
import Logo from "../assets/images/banks-logo.png"

export default function Footer() {
  return (
    <div className="bx--grid footer">
      <div className="bx--row">
        <div className="bx--col bx--col-sm-4">
          <div className="copyright">© 2021 Rolmo</div>
          <div className="footer-links">
            <div>
              <Link href="#">Terms</Link>
            </div>
            <div>
              <Link href="#">Privacy</Link>
            </div>
            <div>
              <Link href="#">Account</Link>
            </div>
            <div>
              <Link href="#">Contact</Link>
            </div>
          </div>
        </div>
        <div className="flex-center bx--col bx--col-sm-4">
          <div className="bank-logo-title">We accept</div>
          <img className="bank-logo" src={Logo} alt="bank" />
        </div>
      </div>
    </div>
  )
}
