import React from "react"

const courses = [
  {
    image: require("../assets/images/purchased-1.jpg"),
    valid: "26 Jan 2022"
  },
  {
    image: require("../assets/images/purchased-2.jpg"),
    valid: "26 Jan 2022"
  },
  {
    image: require("../assets/images/purchased-3.jpg"),
    valid: "26 Jan 2022"
  },
  {
    image: require("../assets/images/purchased-4.jpg"),
    valid: "26 Jan 2022"
  },
  {
    image: require("../assets/images/purchased-5.jpg"),
    valid: "26 Jan 2022"
  },
  {
    image: require("../assets/images/purchased-6.jpg"),
    valid: "26 Jan 2022"
  }
]

export default function Purchased() {
  return (
    <div className="purchased">
      <h2>Purchased</h2>
      <div className="purchased-courses">
        {courses?.map((item, index) => (
          <div className="purchased-course" key={index}>
            <img src={item.image?.default} alt={`course ${index}`} />
            <p>{`Available until ${item.valid}`}</p>
          </div>
        ))}
      </div>
    </div>
  )
}
