import React, { useState } from "react"
import lesson1 from "../assets/images/lesson-1.jpg"
import lesson2 from "../assets/images/lesson-2.jpg"
import lesson3 from "../assets/images/lesson-3.jpg"
import extra1 from "../assets/images/extra-1.jpg"
import extra2 from "../assets/images/extra-2.jpg"
import play from "../assets/images/play.png"
import { Link } from "react-router-dom"
import ExtraPlayer from "./ExtraPlayer"

const collections = [
  {
    id: "slug1",
    name: "Lesson 1",
    title: "Introduction",
    desc:
      "First of all, see on Ary Indra’s perspective on balancing between life at suburb and working for big company in megapolitan city.",

    duration: "11:20",
    poster: lesson1,
    extras: [
      {
        poster: extra1,
        desc:
          "See the scale model of SeloJene with Augmented Reality through your phone.",
        note: "Mobile app only"
      },
      {
        poster: extra2,
        desc: "See the landscape around SeloJene with 360 Virtual Reality",
        note: ""
      }
    ]
  },
  {
    id: "slug2",
    name: "Lesson 2",
    title: "Life lesson",
    desc:
      "Ary Indra talks about the childhood, early career, and his tipping point.",
    duration: "21:15",
    poster: lesson2
  },
  {
    id: "slug3",
    name: "Lesson 3",
    title: "Facade (360° Video)",
    desc:
      'The purpose of using "Nako Glass" is to create cross vertilation inside the house.',
    duration: "19:40",
    poster: lesson3
  }
]

export default function CourseCollection() {
  const [open, setOpen] = useState()

  const handleOpenModal = () => {
    setOpen(true)
  }

  const handleCloseModal = () => {
    setOpen(false)
  }

  return (
    <div className="course-collection">
      <ExtraPlayer open={open} onClose={handleCloseModal} />
      {collections.map((item) => (
        <div key={item.id} className="collection-container">
          <h4>{item.name}</h4>
          <div className="lesson-container">
            <Link to={`/course/${item.id}`}>
              <div className="lesson-thumbnail">
                <img src={item.poster} alt={item.name} />
                <div className="play-icon-container flex-center">
                  <img src={play} alt="play" />
                </div>
              </div>
            </Link>
            <div className="lesson-desc">
              <h4>{item.title}</h4>
              <p>{item.desc}</p>
              <p className="lesson-duration">{item.duration}</p>
            </div>
          </div>
          {item?.extras?.length && (
            <div className="extras-container">
              <h4>Extras</h4>
              {item.extras.map((item, index) => (
                <div key={index} className="extra-container">
                  <div className="extra-thumbnail" onClick={handleOpenModal}>
                    <img src={item.poster} alt={item.name} />
                  </div>
                  <div>
                    <p>{item.desc}</p>
                    <p className="extra-note">{item.note}</p>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      ))}
    </div>
  )
}
